    function selectTrain(id){const trainId=String(id).endsWith('车')?String(id):`${id}车`,t=liveState?.trains.find(item=>item.id===trainId);if(!t)return;selectedTrainId=trainId;document.querySelectorAll('.train').forEach(x=>x.classList.toggle('selected',x.dataset.train===trainId));$('trainName').textContent=t.id;$('trainSpeed').textContent=t.speedKmh.toFixed(1);$('trainState').textContent=t.blockedReason||t.status;$('direction').textContent=t.direction;$('section').textContent=`Seg ${t.segmentId} / ${t.offset.toFixed(1)} m`;$('nextStation').textContent=t.targetStation||'待设置';$('distance').textContent=t.targetDistance==null?'--':`${t.targetDistance.toFixed(0)} m`;$('limit').textContent=`${t.speedLimitKmh.toFixed(0)} km/h`;$('tractionBrake').textContent=`${t.tractiveForceKn.toFixed(0)} / ${t.brakeForceKn.toFixed(0)} kN`;$('overviewPower').textContent=liveState.power.label;$('overviewDoors').textContent=t.doors.left?'左门开启':t.doors.right?'右门开启':'关闭锁闭';$('speedBar').style.width=`${Math.min(100,t.speedKmh/Math.max(1,t.speedLimitKmh)*100)}%`;const monitor=$('monitorTrainSelect');if(monitor){monitor.value=trainId;renderTrainMonitor(t)}}
