      document.querySelectorAll('#subpage [data-power]').forEach(btn=>btn.onclick=async()=>{if(btn.dataset.power==='POWER_OFF'&&!confirm(`确认执行全线断电？\n\n当前状态：${liveState?.power?.label||'未知'}\n影响范围：所有在线列车立即切除牵引\n恢复方式：点击“恢复供电”，约 3 秒后恢复正常`))return;const result=await api('/api/power',{method:'POST',body:JSON.stringify({status:btn.dataset.power})});if(result.ok){document.querySelectorAll('#subpage [data-power]').forEach(x=>x.classList.remove('active'));btn.classList.add('active')}});
      const addForm=$('addTrainForm');if(addForm){const station=$('newTrainStation');station.innerHTML=(liveState?.stations||[]).map(s=>`<option value="${s.id}">${escapeHtml(s.name)}</option>`).join('');addForm.onsubmit=addTrain;$('removeTrainBtn').onclick=removeSelectedTrain;}
