      socket.onopen=()=>{if(snapshotTimer){clearInterval(snapshotTimer);snapshotTimer=null}if(reconnectTimer){clearTimeout(reconnectTimer);reconnectTimer=null}$('backendStatus').innerHTML='<i class="dot"></i>仿真核心正常'};
