      socket.onclose=()=>{$('backendStatus').innerHTML='<i class="dot off"></i>实时通道断开 · 快照轮询';if(!snapshotTimer)snapshotTimer=setInterval(refreshSnapshot,1000);if(!reconnectTimer)reconnectTimer=setTimeout(()=>{reconnectTimer=null;connectBackend()},3000)};
