    function renderSignalState(){const list=$('signalDeviceList');if(!list||!liveState)return;const occupancy=Object.entries(liveState.occupancy||{}),locks=Object.entries(liveState.locks||{}),restricted=(liveState.signals||[]).filter(signal=>signal.aspect!=='GREEN').slice(0,12),items=[];occupancy.forEach(([segment,owners])=>items.push(`<div class="device"><code>SEG ${escapeHtml(segment)}</code><div>轨道区段<br><small>占用列车 ${escapeHtml(owners.join('、'))}</small></div><span class="status stop">占用</span></div>`));locks.forEach(([segment,owner])=>items.push(`<div class="device"><code>SEG ${escapeHtml(segment)}</code><div>进路锁闭<br><small>锁闭列车 ${escapeHtml(owner)}</small></div><span class="status warn">锁闭</span></div>`));restricted.forEach(signal=>{const isRed=signal.aspect==='RED';items.push(`<div class="device"><code>${escapeHtml(signal.id)}</code><div>信号机 · ${isRed?'红灯':'黄灯'}<br><small>区段 ${escapeHtml(signal.segmentId)} · ${escapeHtml(signal.direction)}</small></div><span class="status ${isRed?'stop':'warn'}">${isRed?'防护':'注意'}</span></div>`)});list.innerHTML=items.join('')||'<div class="log-empty">当前无占用、锁闭或限制信号</div>';$('signalDeviceCount').textContent=`${items.length} 项`;$('signalSummary').textContent=`道岔 ${liveState.trackSummary?.switchCount??0} · 信号机 ${liveState.trackSummary?.signalCount??liveState.signals.length} · 默认显示关键设备`;$('signalRealtimeState').textContent='实时同步';renderSignalTrack();}

    function buildSignalScale(line,all){const min=Math.min(...all.map(link=>link.start_m)),max=Math.max(...all.map(link=>link.end_m)),stations=(line.stations||[]).slice().sort((a,b)=>a.position-b.position),anchors=[min,...stations.map(station=>station.position).filter(position=>position>min&&position<max),max].filter((value,index,array)=>!index||Math.abs(value-array[index-1])>.01),xs=anchors.map((_,index)=>68+index/Math.max(1,anchors.length-1)*964);return position=>{if(position<=anchors[0])return xs[0];if(position>=anchors.at(-1))return xs.at(-1);const right=anchors.findIndex(value=>value>=position),left=Math.max(0,right-1),ratio=(position-anchors[left])/Math.max(.001,anchors[right]-anchors[left]);return xs[left]+ratio*(xs[right]-xs[left])}}
    function primarySignalKeys(signals){const selected=new Set();['down','up'].forEach(direction=>{const items=signals.filter(signal=>signal.direction===direction&&signal.linkPosition!=null).sort((a,b)=>a.linkPosition-b.linkPosition),kept=[];items.forEach(signal=>{const previous=kept.at(-1);if(!previous||signal.linkPosition-previous.linkPosition>=300){kept.push(signal)}else if(previous.aspect==='GREEN'&&signal.aspect!=='GREEN'){kept[kept.length-1]=signal}});kept.forEach(signal=>selected.add(signal.key))});return selected}
    function renderSchematicSwitches(line, parts, downY, upY) {
      const components = new Map((line.switchComponents || []).map(component => [component.id, component]));
      const activeRoutes = liveState?.operatorRoutes || [];
      const routeLocked = ids => activeRoutes.some(active => active.componentIds?.some(id => ids.includes(Number(id))));
      const pointLocked = point => activeRoutes.some(active => active.branchSegmentIds?.includes(point.reverseSegmentId));
      const marker = (point, x, y) => point && parts.push(`<path class="signal-switch switch-marker${pointLocked(point)?' locked':''}" tabindex="0" role="button" data-switch-id="${point.switchId}" d="M${x} ${y-6} l6 6 -6 6 -6 -6 Z"><title>道岔 ${escapeHtml(point.name)}</title></path>`);
      const route = (path, ids, label) => {
        const locked = routeLocked(ids) ? ' locked' : '';
        parts.push(`<path class="signal-switch switch-route${locked}" d="${path}"/><path class="signal-switch switch-route-hit${locked}" tabindex="0" role="button" aria-label="${label}" data-switch-component="${ids.join(',')}" data-route-label="${label}" d="${path}"/>`);
      };
      const addCrossover = (ids, left, right, label) => {
        const points = ids.flatMap(id => components.get(id)?.points || []);
        const down = points.filter(point => point.direction === 'down').slice(0, 2);
        const up = points.filter(point => point.direction === 'up').slice(0, 2);
        if (down.length < 2 || up.length < 2) return;
        route(`M${left} ${downY} L${right} ${upY}`, ids, label);
        route(`M${left} ${upY} L${right} ${downY}`, ids, label);
        parts.push(`<text class="switch-route-label" x="${(left+right)/2}" y="${(downY+upY)/2+4}" text-anchor="middle">${label}</text>`);
        marker(down[0], left, downY); marker(down[1], right, downY);
        marker(up[0], left, upY); marker(up[1], right, upY);
      };
      const addSingle = (id, left, right, label) => {
        const component = components.get(id), points = component?.points || [];
        if (points.length !== 2) return;
        const firstY = points[0].direction === 'down' ? downY : upY;
        const secondY = points[1].direction === 'down' ? downY : upY;
        route(`M${left} ${firstY} L${right} ${secondY}`, [id], label);
        parts.push(`<text class="switch-route-label" x="${(left+right)/2}" y="${(downY+upY)/2+4}" text-anchor="middle">${label}</text>`);
        marker(points[0], left, firstY); marker(points[1], right, secondY);
      };
      const addStub = (id, start, base, end, label, sign) => {
        const component = components.get(id), point = component?.points[0];
        if (!point) return;
        const branchY = base + sign * 62, knee = start + (end > start ? 24 : -24);
        const path = `M${start} ${base} L${knee} ${branchY} L${end} ${branchY}`;
        route(path, [id], label);
        parts.push(`<line class="signal-switch switch-buffer" x1="${end}" y1="${branchY-8}" x2="${end}" y2="${branchY+8}"/><text class="switch-side-label" x="${(knee+end)/2}" y="${branchY+(sign<0?-10:17)}" text-anchor="middle">${label}</text>`);
        marker(point, start, base);
      };

      // 只选择后端真实存在的组件，坐标仍按全线示意图做均衡排布。
      addCrossover([4, 5], 175, 250, 'SW-0100');
      addSingle(8, 330, 395, 'SW-0101');
      addCrossover([9], 550, 635, 'SW-0102');
      addCrossover([13, 14], 800, 875, 'SW-0103');
      addStub(6, 145, downY, 235, '上行调车线', -1);
      addStub(15, 905, downY, 985, '下行调车线', -1);
      addStub(10, 700, upY, 820, '站台侧线', 1);
    }
    function renderSignalTrack(){const svg=$('signalTrackSvg'),line=liveState?.line;if(!svg||!line)return;const directions=line.directions||{},all=[...(directions.down||[]),...(directions.up||[])];if(!all.length){svg.innerHTML='<text x="550" y="215" text-anchor="middle" fill="#73858e">后端未提供 Link 主线</text>';return;}const downY=150,upY=280,x=buildSignalScale(line,all),occupancy=liveState.occupancy||{},locks=liveState.locks||{},parts=['<text class="direction-label" x="20" y="154">下行 →</text><text class="direction-label" x="20" y="284">← 上行</text>'];[['down',downY],['up',upY]].forEach(([direction,y])=>(directions[direction]||[]).forEach(link=>{const id=String(link.link_id),color=occupancy[id]?'#ff5b62':locks[id]?'#e9b44c':'#a8b3b8',width=occupancy[id]?8:locks[id]?7:4;parts.push(`<line class="signal-section" tabindex="0" role="button" data-signal-link="${id}" data-direction="${direction}" data-state-stroke="${color}" data-state-width="${width}" x1="${x(link.start_m).toFixed(1)}" y1="${y}" x2="${x(link.end_m).toFixed(1)}" y2="${y}" stroke="${color}" stroke-width="${width}"/><text class="signal-link-label" x="${x((link.start_m+link.end_m)/2).toFixed(1)}" y="${y-11}" text-anchor="middle">${id}</text>`)}));(line.stations||[]).forEach(station=>{const sx=x(station.position);parts.push(`<g class="signal-station"><circle cx="${sx.toFixed(1)}" cy="${downY}" r="5"/><circle cx="${sx.toFixed(1)}" cy="${upY}" r="5"/><text class="station-top-label" x="${sx.toFixed(1)}" y="38" text-anchor="middle">${escapeHtml(station.name)}</text></g>`)});renderSchematicSwitches(line,parts,downY,upY);const mappedSignals=(liveState.signals||[]).filter(signal=>signal.linkPosition!=null),primary=primarySignalKeys(mappedSignals);mappedSignals.forEach(signal=>{const sx=x(signal.linkPosition),trackY=signal.direction==='down'?downY:upY,lampY=signal.direction==='down'?downY-28:upY+28,color=signal.aspect==='RED'?'#ff5b62':signal.aspect==='YELLOW'?'#e9b44c':'#5bd28a',main=primary.has(signal.key),detailClass=main?'signal-primary':'signal-secondary',labelY=signal.direction==='down'?lampY-16:lampY+20;parts.push(`<g class="signal-symbol ${detailClass}"><line x1="${sx.toFixed(1)}" y1="${trackY}" x2="${sx.toFixed(1)}" y2="${lampY+8*(signal.direction==='down'?1:-1)}"/><rect class="signal-housing" x="${(sx-5).toFixed(1)}" y="${(lampY-9).toFixed(1)}" width="10" height="18" rx="2"/><circle class="signal-device" tabindex="0" role="button" aria-label="信号机 ${escapeHtml(signal.id)}，${signal.aspect}" data-signal-key="${escapeHtml(signal.key)}" data-signal-id="${escapeHtml(signal.id)}" cx="${sx.toFixed(1)}" cy="${lampY}" r="3.5" fill="${color}"><title>${escapeHtml(signal.id)} · ${signal.aspect}</title></circle><text class="signal-name" x="${sx.toFixed(1)}" y="${labelY}" text-anchor="middle">${escapeHtml(signal.id)}</text></g>`)});(liveState.trains||[]).filter(train=>train.linkPosition!=null).forEach(train=>{const tx=x(train.linkPosition),ty=train.directionCode>=0?downY:upY;parts.push(`<g class="signal-train" transform="translate(${tx.toFixed(1)} ${ty})"><rect x="-21" y="-13" width="42" height="26" rx="3"/><text y="4" text-anchor="middle">${escapeHtml(train.id)}</text></g>`)});svg.innerHTML=parts.join('');applyTrackZoom();SignalCenter.bindCanvas(liveState);}
    function renderLogs(){if(!liveState)return;const trainIds=liveState.trains.map(t=>t.id);$('logFilters').innerHTML=`<button class="${logTrain===''?'active':''}" data-log-train="">全部日志</button><button class="${logTrain==='system'?'active':''}" data-log-train="system">系统</button>${trainIds.map(id=>`<button class="${logTrain===id?'active':''}" data-log-train="${escapeHtml(id)}">${escapeHtml(id)}</button>`).join('')}`;const filtered=(liveState.events||[]).filter(e=>logTrain===''||(logTrain==='system'?!e.train_id:e.train_id===logTrain)).slice().reverse();$('logCount').textContent=`${filtered.length} 条 · 最近 120 条`;if(!filtered.length){$('eventLog').innerHTML='<div class="log-empty">当前筛选下暂无日志</div>';return;}$('eventLog').innerHTML=filtered.map(e=>{const level=e.severity==='CRITICAL'?'critical':e.severity==='WARNING'?'warn':'ok';const minutes=String(Math.floor(e.timestamp/60)).padStart(2,'0'),secs=(e.timestamp%60).toFixed(1).padStart(4,'0'),hasPosition=Number.isFinite(Number(e.position))&&Number(e.position)!==0,hasSpeed=Number.isFinite(Number(e.speed))&&Number(e.speed)!==0;return `<div class="log-row"><time>${minutes}:${secs}</time><span class="${level}">${escapeHtml(e.severity)}</span><span>${escapeHtml(e.event_type||'事件')}</span><span>${escapeHtml(e.train_id||'系统')}</span><span title="${escapeHtml(e.description)}">${escapeHtml(e.description)}</span><span>${escapeHtml(e.source||'system')}</span><span>${escapeHtml(e.entity_id||'—')}</span><span>${hasPosition?`${Number(e.position).toFixed(1)} m`:'—'}</span><span>${hasSpeed?`${(Number(e.speed)*3.6).toFixed(1)} km/h`:'—'}</span></div>`}).join('');}
    function applyTrackZoom(){const s=zoomState;const svg1=$('overviewTrackSvg'),svg2=$('signalTrackSvg');if(svg1){svg1.style.transform=`scale(${s.track.zoom})`;svg1.style.transformOrigin=`0 274px`;if(s.track.panX)svg1.style.marginLeft=s.track.panX+'px'}if(svg2){svg2.style.transform=`scale(${s.signal.zoom})`;svg2.style.transformOrigin=`0 215px`;svg2.classList.toggle('signal-detailed',s.signal.zoom>=1.55);if(s.signal.panX)svg2.style.marginLeft=s.signal.panX+'px'}};function bindZoom(container,state){if(!container||container.dataset.zoomBound)return;container.dataset.zoomBound='1';container.addEventListener('wheel',e=>{e.preventDefault();const rect=container.getBoundingClientRect(),mx=e.clientX-rect.left,old=state.zoom;state.zoom=Math.max(0.3,Math.min(4,old*(e.deltaY>0?0.9:1.1)));const scale=state.zoom/old;state.panX=mx-scale*(mx-state.panX);applyTrackZoom()},{passive:false});container.addEventListener('mousedown',e=>{if(e.button!==0)return;trackDragging=true;trackDragStartX=e.clientX;trackDragPanX=state.panX;trackDragTarget=state;container.style.cursor='grabbing'});container.addEventListener('dblclick',()=>{state.zoom=1;state.panX=0;applyTrackZoom()})};document.addEventListener('mousemove',e=>{if(!trackDragging||!trackDragTarget)return;trackDragTarget.panX=trackDragPanX+(e.clientX-trackDragStartX);applyTrackZoom()});document.addEventListener('mouseup',()=>{if(trackDragging){trackDragging=false;trackDragTarget=null;document.querySelectorAll('.map,.signal-canvas').forEach(el=>el.style.cursor='')}});document.addEventListener('DOMContentLoaded',()=>{const map=document.querySelector('.map');if(map)bindZoom(map,zoomState.track);const observer=new MutationObserver(()=>{const canvas=document.querySelector('.signal-canvas');if(canvas)bindZoom(canvas,zoomState.signal)});observer.observe(document.getElementById('subpage'),{childList:true,subtree:true})});connectBackend();
